    'skills-priority': { category: 'CV', title: 'Dai priorità alle competenze chiave', description: 'Scegli le 8-12 competenze più adatte al ruolo target.', why: 'Troppe competenze generiche indeboliscono il posizionamento.', task: 'Rimuovi competenze deboli o obsolete e mantieni quelle più allineate al ruolo.', exampleBefore: 'Microsoft Office, Windows, Comunicazione, Teamwork, Hardware, Software, IT.', exampleAfter: 'Microsoft Intune, Autopilot, ITSM, Jira, Freshdesk, ITIL, Sicurezza endpoint, Microsoft 365, Gestione SLA.' },
    'achievement-metrics': { category: 'CV', title: 'Aggiungi numeri ai risultati', description: 'Aggiungi una prova misurabile alla tua esperienza.', why: 'I numeri rendono il contributo più credibile.', task: 'Aggiungi una metrica: team, ticket, tempi di risoluzione, dispositivi, utenti, budget o durata progetto.', exampleBefore: 'Miglioramento dei processi supporto.', exampleAfter: 'Standardizzati processi supporto per oltre 500 utenti, migliorando la visibilità SLA e riducendo incidenti ricorrenti.' },
    'application-message': { category: 'Ricerca lavoro', title: 'Scrivi un messaggio di candidatura più forte', description: 'Crea un messaggio breve per una candidatura o recruiter.', why: 'Un messaggio chiaro può aumentare le risposte.', task: 'Scrivi 4 righe: interesse, esperienza rilevante, prova e invito al colloquio.', exampleBefore: 'Buongiorno, sono interessato a questa posizione. In allegato il CV.', exampleAfter: 'Buongiorno, sono interessato al ruolo di IT Manager. Porto una forte esperienza in leadership supporto, gestione endpoint e operazioni ITSM. Mi piacerebbe confrontarmi su come migliorare service delivery ed esperienza utente.' }
