    'cv-summary-focus': { category: 'CV', title: 'Clarifique o resumo profissional', description: 'Torne o resumo mais focado e fácil de ler.', why: 'Um bom resumo mostra o seu valor em segundos.', task: 'Escreva um resumo de 3 linhas com função, forças e valor mensurável.', exampleBefore: 'Profissional IT experiente com boas competências técnicas.', exampleAfter: 'IT Manager com mais de 10 anos de experiência em suporte, infraestrutura e tecnologias workplace. Forte em Intune, ITSM, gestão endpoint e service delivery.' },
    'interview-pitch': { category: 'Entrevista', title: 'Prepare o pitch de 30 segundos', description: 'Crie uma resposta clara para “Fale-me sobre si”.', why: 'A primeira resposta define o tom da entrevista.', task: 'Escreva um pitch curto sobre quem é, o que faz bem e a função que procura.', exampleBefore: 'Trabalho em IT e fiz suporte e gestão.', exampleAfter: 'Sou IT Manager com forte experiência em operações de suporte, gestão endpoint e service delivery. Ajudo equipas a melhorar a experiência do utilizador, estruturar processos de suporte e entregar serviços IT fiáveis.' },
    'skills-priority': { category: 'CV', title: 'Priorize competências-chave', description: 'Escolha as 8 a 12 competências mais alinhadas com a função alvo.', why: 'Demasiadas competências genéricas diluem o posicionamento.', task: 'Remova competências fracas ou antigas e mantenha as mais relevantes.', exampleBefore: 'Microsoft Office, Windows, Comunicação, Trabalho em equipa, Hardware, Software, IT.', exampleAfter: 'Microsoft Intune, Autopilot, ITSM, Jira, Freshdesk, ITIL, Segurança endpoint, Microsoft 365, Gestão SLA.' },
    'achievement-metrics': { category: 'CV', title: 'Adicione números às conquistas', description: 'Adicione uma prova mensurável à sua experiência.', why: 'Números tornam a contribuição mais credível.', task: 'Adicione uma métrica: equipa, tickets, tempo de resolução, dispositivos, utilizadores, orçamento ou duração do projeto.', exampleBefore: 'Melhoria dos processos de suporte.', exampleAfter: 'Padronizei processos de suporte para mais de 500 utilizadores, melhorando a visibilidade SLA e reduzindo incidentes recorrentes.' },
    'application-message': { category: 'Procura de emprego', title: 'Escreva uma mensagem de candidatura mais forte', description: 'Crie uma mensagem curta para candidatura ou recrutador.', why: 'Uma mensagem clara pode aumentar respostas.', task: 'Escreva 4 linhas: interesse, experiência relevante, prova e convite para conversa.', exampleBefore: 'Olá, tenho interesse nesta vaga. Segue o meu CV.', exampleAfter: 'Olá, tenho interesse na função de IT Manager. Trago forte experiência em liderança de suporte, gestão endpoint e operações ITSM. Gostaria de conversar sobre como posso melhorar service delivery e experiência do utilizador.' }
