export function getPremiumTranslation(lang, key, fallback) {
  return premiumTranslations[lang]?.[key] || premiumTranslations.en?.[key] || fallback || key
}

export function getLocalizedChallenge(challenge, lang) {
  return { ...challenge, ...(challengeTranslations[lang]?.[challenge.id] || {}) }
}
